/**
 * MIA-SADM — Extreme Minimal Decoder
 * Version: QR VISUAL-ONLY + CID Parent/Child Compliance
 * Mode: Run Once for All Items
 */

// ---------------- Helpers ----------------
function splitSafe(value, sep, size) {
  const arr = (value || "").split(sep);
  while (arr.length < size) arr.push("");
  return arr;
}
const f = v => isNaN(parseFloat(v)) ? 0.0 : parseFloat(v);
const i = v => isNaN(parseInt(v, 10)) ? 0 : parseInt(v, 10);
const b = v => v === "1";

// ---------------- Input ----------------
const input = $input.first().json;

// ---------------- Find EXTREME JSON ----------------
function findJsonString(obj) {
  if (!obj) return null;
  if (typeof obj === "string") {
    const m = obj.match(/\{[\s\S]*\}$/);
    return m ? m[0] : null;
  }
  if (typeof obj === "object") {
    for (const k of Object.keys(obj)) {
      const found = findJsonString(obj[k]);
      if (found) return found;
    }
  }
  return null;
}

const raw = findJsonString(input);
if (!raw) throw new Error("No EXTREME JSON found");

let src;
try {
  src = JSON.parse(raw);
} catch {
  throw new Error("Invalid EXTREME JSON");
}

// ---------------- Maps ----------------
const docTypeMap = { mc: "medical_certificate", ot: "other" };
const attTypeMap = { c: "consultation", e: "exam", p: "companion", h: "hospitalization" };
const manipulationMap = { B: "blur", W: "white_patch", O: "obfuscation", T: "texture_inconsistency" };

// ---------------- Decode primitives ----------------
const [doctorName, crmNumber, crmState, rqeNumber] = splitSafe(src.d, "|", 4);
const [issuerName, issuerCity, issuerState, issuerCnpj] = splitSafe(src.i, "|", 4);
const [attType, attDate, attTime, leaveDays, leaveStart, leaveEnd] = splitSafe(src.a, "|", 6);

// UPDATED: CID now has VERSION | PARENT | CHILD
const [cidVerRaw, cidParent, cidChild] = splitSafe(src.cid, "|", 3);

const [capType, capDevice, capNotes] = splitSafe(src.cap, "|", 3);
const [ocrStatus, ocrEngine, ocrLang, ocrConf, ocrMatch, ocrMismatch] = splitSafe(src.ocr, "|", 6);
const deArr = splitSafe(src.de, "|", 12).map(b);
const [faStatus, faDigital, faPhysical, faAI, lowRes, blur, noise, occlusion, faNotes] =
  splitSafe(src.fa, "|", 9);

// QR — VISUAL ONLY (payload + bbox enforced to zero)
const [qrPresent, qrReadableVisual, , qrNotes] = splitSafe(src.qr, "|", 8);

// ---------------- Stamp & Signature Validity ----------------
const hasStamp = deArr[3];
const hasSignature = deArr[4];

const stampOrSignatureDegraded =
  faDigital === "strong" ||
  faPhysical === "strong" ||
  b(blur) ||
  b(lowRes);

const stampValid = hasStamp && !stampOrSignatureDegraded;
const signatureValid = hasSignature && !stampOrSignatureDegraded;

// ---------------- QR Conditional Logic (VISUAL ONLY) ----------------
let qrSufficientAsSignature = true;
let authFailureReason = "";

if (!stampValid && !signatureValid) {
  if (!b(qrPresent)) {
    qrSufficientAsSignature = false;
    authFailureReason = "stamp_and_signature_invalid_and_qr_missing";
  } else if (!b(qrReadableVisual)) {
    qrSufficientAsSignature = false;
    authFailureReason = "stamp_and_signature_invalid_and_qr_visually_unreadable";
  }
}

// ---------------- Build Canonical ----------------
const output = {
  document_metadata: {
    document_type: docTypeMap[src.t] || "other",
    is_medical_certificate: src.t === "mc",
    analysis_timestamp: new Date().toISOString()
  },

  capture: {
    capture_type: capType || "unknown",
    device_info: capDevice || "",
    capture_quality_notes: capNotes || ""
  },

  ocr: {
    status: ocrStatus || "unknown",
    engine: ocrEngine || "",
    language_detected: ocrLang || "",
    confidence_avg: f(ocrConf),
    match_score: f(ocrMatch),
    mismatch_fields: (ocrMismatch || "").split("+").filter(Boolean)
  },

  patient_identification: {
    patient_name: src.p || ""
  },

  medical_professional: {
    doctor_name: doctorName || "",
    crm_number: crmNumber || "",
    crm_state: crmState || "",
    specialty_registration: rqeNumber || ""
  },

  issuer_information: {
    issuer_name: issuerName || "",
    city: issuerCity || "",
    state: issuerState || "",
    cnpj: issuerCnpj || ""
  },

  attendance_information: {
    attendance_type: attTypeMap[attType] || "",
    attendance_date: attDate || "",
    attendance_time: attTime || "",
    leave: {
      days: i(leaveDays),
      start_date: leaveStart || "",
      end_date: leaveEnd || ""
    }
  },

  medical_classification: {
    cid_version:
      cidVerRaw === "CID10" ? "CID-10" :
      cidVerRaw === "CID11" ? "CID-11" : "",
    cid_parent: cidParent || "",
    cid_child: cidChild || ""
  },

  document_elements: {
    has_logo: deArr[0],
    has_letterhead: deArr[1],
    has_mandatory_fields: deArr[2],
    has_stamp: hasStamp,
    has_signature: hasSignature,
    stamp_valid: stampValid,
    signature_valid: signatureValid,
    has_disclaimer: deArr[5],
    has_issuer_data: deArr[6],
    has_doctor_data: deArr[7],
    has_patient_data: deArr[8],
    has_attendance_data: deArr[9],
    has_disease_data: deArr[10],
    has_locality_data: deArr[11]
  },

  forensic_analysis: {
    status: faStatus || "not_started",
    digital_manipulation_indicators: faDigital || "none",
    physical_manipulation_indicators: faPhysical || "none",
    ai_generation_or_reconstruction_indicators: faAI || "none",
    visual_quality_issues: {
      low_resolution: b(lowRes),
      blur: b(blur),
      noise: b(noise),
      occlusion: b(occlusion)
    },
    forensic_notes: faNotes || ""
  },

  qr_validation: {
    qr_present: b(qrPresent),
    qr_readable_visual_opinion: b(qrReadableVisual),
    qr_target_url: "",
    qr_notes: qrNotes || "",
    qr_bbox: { x: 0, y: 0, width: 0, height: 0 },
    qr_sufficient_as_signature_visual_only: qrSufficientAsSignature
  },

  manipulation_analysis: {
    detected: src.m?.startsWith("1"),
    manipulation_types: (splitSafe(src.m, "|", 4)[1] || "")
      .split("+")
      .map(t => manipulationMap[t])
      .filter(Boolean),
    impacted_fields: (splitSafe(src.m, "|", 4)[2] || "").split("+").filter(Boolean),
    confidence: f(splitSafe(src.m, "|", 4)[3])
  },

  image_scores: {
    consistency: f(splitSafe(src.s, "|", 3)[0]),
    completeness: f(splitSafe(src.s, "|", 3)[1]),
    image_quality: f(splitSafe(src.s, "|", 3)[2])
  },

  preliminary_recommendation: {
    visual_risk: splitSafe(src.r, "|", 3)[0] || "",
    recommended_action: splitSafe(src.r, "|", 3)[1] || "",
    reason_code:
      splitSafe(src.r, "|", 3)[2] ||
      authFailureReason ||
      ""
  }
};

// ---------------- Return ----------------
return [{ json: output }];

if (!$("Dados CNPJ").first().json.success) {
  return $("Dados CNPJ").first()
 } else {return JSON.parse('{}')}
